{{-- OG-image template voor de homepage (1200x630). Inline styles zodat het
     screenshot-resultaat niet afhangt van beschikbare Tailwind-utilities. --}}
<div style="width:1200px;height:630px;box-sizing:border-box;display:flex;flex-direction:column;justify-content:center;padding:90px;background:linear-gradient(135deg,#0f172a 0%,#134e4a 100%);color:#ffffff;font-family:'Instrument Sans',system-ui,-apple-system,sans-serif;">
    <div style="font-size:34px;font-weight:600;letter-spacing:.08em;color:#5eead4;text-transform:uppercase;">Volg je raad</div>
    <h1 style="font-size:82px;font-weight:800;line-height:1.05;margin:28px 0 0;max-width:960px;">Raadsvergaderingen, automatisch samengevat.</h1>
    <p style="font-size:36px;line-height:1.3;color:#cbd5e1;margin:32px 0 0;max-width:960px;">Heldere samenvattingen in je inbox — rechtstreeks uit de officiële bronnen.</p>
</div>
